{
  "matrix_id": "CR-202-options",
  "options": [
    {"id": "opt-A", "name": "Re-baseline: add full 7-year retention pipeline", "description": "Build cold-storage tier; migrate all 11 systems."},
    {"id": "opt-B", "name": "Reduce scope: 7-year retention for billing-domain only", "description": "Apply only to in-scope regulatory entities; document exclusions."},
    {"id": "opt-C", "name": "Defer: park CR until regulator clarifies effective date", "description": "Park-the-CR with monitoring; revisit Q4."}
  ],
  "scores": [
    {"option_id": "opt-A", "cost": "L", "value": "H", "risk": "M", "rationale": "Largest cost; full compliance coverage; medium delivery risk."},
    {"option_id": "opt-B", "cost": "M", "value": "M", "risk": "M", "rationale": "Lower cost; partial coverage may be insufficient on audit."},
    {"option_id": "opt-C", "cost": "S", "value": "S", "risk": "H", "rationale": "Cheapest now; high risk if regulator acts within 12 months."}
  ],
  "recommendation": "Option B — reduce scope to billing-domain only; revisit when clarification arrives",
  "rationale": "Score comparison favours B: cost/value tied to A but B reduces delivery risk on a tight timeline; risk on coverage gap is acceptable since billing-domain covers 85% of regulated transactions per traceability graph.",
  "approver": "Steering committee (chair: Andriy Hrytsenko CTO)",
  "decision_by": "2026-06-15",
  "owner": "ruslan@faion.net",
  "version": "1.1.0",
  "last_reviewed": "2026-05-23"
}
